qry:select.qry:xquery:
					for $r in sql('
			SELECT 
			t0.oi_proyecto as oi_proyecto
			FROM 
			PRY01_PROYECTOS as t0
			WHERE 1=1
      {%? (#PARAM:@f_inicio_hasta!='') {% AND t0.f_inicio <= {#PARAM:@f_inicio_hasta} %} {% %} %}
      {%? (#PARAM:@f_inicio_desde!='') {% AND t0.f_inicio >= {#PARAM:@f_inicio_desde} %} {% %} %}
      {%? (#PARAM:@f_fin_hasta!='') {% AND t0.f_fin <= {#PARAM:@f_fin_hasta} %} {% %} %}
      {%? (#PARAM:@f_fin_desde!='') {% AND t0.f_fin >= {#PARAM:@f_fin_desde} %} {% %} %}
      {%? (string(#PARAM:@c_proyecto)!='') {% AND CONTAIN(t0.c_proyecto,{#PARAM:@c_proyecto}) %} {% %} %}
      {%? (string(#PARAM:@d_proyecto)!='') {% AND CONTAIN(t0.d_proyecto,{#PARAM:@d_proyecto}) %} {% %} %}
			{%? (string(#PARAM:@oi_recurso)!='') {% AND t0.oi_recurso = {#PARAM:@oi_recurso} %} {% %} %}
			{%? (string(#PARAM:@oi_cliente)!='') {% AND t0.oi_cliente = {#PARAM:@oi_cliente} %} {% %} %}
      {%? (string(#PARAM:EST/C/@id)!='') {% AND CONTAIN({#PARAM:EST/C/@id},t0.c_estado) %} {%  %} %}
      {%? (string(#PARAM:TPROYS/C/@id)!='') {% AND t0.oi_tipo_proyecto IN ({%=string(#PARAM:TPROYS/C/@id) %}) %} {%  %} %}
      ORDER BY 
			oi_proyecto asc')/ROWS/ROW
